INSERT INTO public.products VALUES ('09b2aab0-251c-4447-bf97-e589da6544d9', 'La Roche-Posay Pigmentclar Eyes Brightening Eye Cream', 'ca37042e-8c7c-4e5f-8e51-e1e94b387385', 'Eye Care', 'A brightening eye cream designed to target dark circles and uneven pigmentation around the delicate eye area. Its gentle formula is suitable for sensitive skin and works to visibly improve eye contour radiance.', 'Ideal for those with dark circles, dullness, and signs of fatigue around the eyes.', 'This product is significantly cheaper in French pharmacies compared to the US, often by 30-40%. Additionally, larger sizes are more commonly available in France.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/la_roche-posay_eye_cream.png');
INSERT INTO public.products VALUES ('a4f04a7e-f291-41c7-95e0-950dce16ee84', 'La Roche-Posay Anthelios Dermo-Pediatrics Spray SPF50+', 'ca37042e-8c7c-4e5f-8e51-e1e94b387385', 'Sunscreen', 'A lightweight, high-protection spray sunscreen designed for both face and body, suitable for sensitive skin. It offers broad-spectrum UVA/UVB protection with EU-exclusive filters and is water-resistant, making it perfect for outdoor activities.', 'Ideal for all skin types, particularly sensitive skin or those seeking high sun protection for face and body. Great for families or travelers spending prolonged time outdoors.', 'This product includes advanced EU-only UV filters such as Mexoryl SX and Tinosorb S, which provide superior UVA protection compared to US formulations. It is also more affordable in French pharmacies compared to US prices.', true, true, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/la_roche-posay_kids_sunscreen_spray.png');
INSERT INTO public.products VALUES ('efe4666b-af5b-4f62-95eb-610a7bf59eaf', 'Lierac Premium Anti-Aging Absolute Cream', '8cebffaa-ef68-4369-a08e-ff9cd70b17e3', 'Moisturizer', 'A luxurious anti-aging face cream formulated with patented peptides and hyaluronic acid to target wrinkles, loss of firmness, and dullness. This rich cream deeply hydrates while addressing multiple signs of aging for a radiant, youthful complexion.', 'Women concerned with wrinkles, fine lines, and loss of elasticity, especially those looking for an all-in-one anti-aging treatment.', 'Lierac products are often priced significantly lower in France compared to US retailers. Additionally, some formulations may differ slightly in the EU, offering additional benefits.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/lierac_premium_cream_jar.png');
INSERT INTO public.products VALUES ('50a94ae3-dacc-47a4-b188-a42ecf27b355', 'Nuxe Nuxuriance Ultra Replenishing Rich Cream', '1dea8445-f3d0-4503-9737-72daffe5fb58', 'Moisturizer', 'A luxurious anti-aging cream that targets wrinkles, loss of firmness, and dullness while intensely moisturizing the skin. Formulated with saffron and bougainvillea bi-floral cells for effective skin rejuvenation.', 'Perfect for mature or dry skin types seeking hydration and anti-aging benefits such as reduced wrinkles and improved skin elasticity.', 'This product is significantly cheaper in French pharmacies compared to US retailers. Additionally, French pharmacies often carry larger sizes of Nuxe products, providing better value.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/nuxe_nuxuriance_jar.png');
