INSERT INTO public.products VALUES ('82f07f7a-cd05-4dcc-8c12-d0ac7e279373', 'SVR Sun Secure Blur SPF50', 'a85a20e0-f130-4c20-9c09-60aa21cbe365', 'Sunscreen', 'SVR Sun Secure Blur SPF50 is a velvety sunscreen that offers broad-spectrum protection against UVA and UVB rays with a unique mousse-to-powder texture. It provides a blurring effect for a smooth, matte finish, ideal as a makeup base or standalone skin perfector.', 'Perfect for those looking for high sun protection with a matte finish, it is suitable for sensitive skin and helps to minimize the appearance of pores.', 'This sunscreen contains advanced EU-only UV filters like Tinosorb S and Uvinul A Plus, which are not available in US sunscreens. Additionally, it is often more affordable in France compared to international retail prices.', true, true, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/svr_sunscreen_spf50_tube.png');
INSERT INTO public.products VALUES ('439be265-0c43-42ee-8599-865a4eb6ceaa', 'Topialyse Essence Hydratante', 'a85a20e0-f130-4c20-9c09-60aa21cbe365', 'Toner', 'Hydrating essence-toner hybrid that delivers instant moisture. Contains hyaluronic acid and niacinamide.', 'Dry skin, dehydrated skin, first step hydration', 'SVR formulas often have higher concentrations than US versions', false, true, false, false, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/svr_topialyse_essence_bottle.png');
INSERT INTO public.products VALUES ('d34e9efc-7eea-434b-b3a3-b0c7b1195c08', 'Uriage Age Lift Smoothing Night Cream', '5f0ab354-d914-4632-b0ee-36881aff538a', 'Moisturizer', 'This anti-aging night cream works to smooth fine lines and wrinkles while firming the skin. Enriched with Uriage Thermal Water, it hydrates deeply and contains retinol-like actives for visible rejuvenation.', 'Ideal for women concerned with fine lines, wrinkles, and loss of firmness, who want a hydrating anti-aging cream for nighttime use.', 'This product is often more affordable in French pharmacies, with a price difference of 20-30% compared to US online retailers. Additionally, the formula includes EU-approved ingredients not always found in US products.', false, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/uriage_age_lift_jar.png');
INSERT INTO public.products VALUES ('75e84c4d-c1f9-426f-9edd-ef9c6f4eb690', 'Vichy Capital Soleil UV-Age Daily SPF50+', 'be047683-8275-4206-837f-9fd9f455a557', 'Sunscreen', 'A lightweight, daily anti-photoaging sunscreen with SPF50+ that combines high sun protection with anti-aging benefits. The formula is enriched with peptides and niacinamide to help prevent wrinkles and dark spots while protecting the skin from UV rays.', 'Ideal for daily use on face and body to protect against sun damage and prevent the signs of aging. Suitable for sensitive skin.', 'This sunscreen often costs significantly less in French pharmacies compared to US retailers, and it features advanced UV filters like Mexoryl XL, which are not available in the US.', true, true, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/vichy_sunscreen_lotion_bottle.png');
