INSERT INTO public.products VALUES ('475d9286-e3a5-4fa5-8f93-a97b7ca3cece', 'Caudalie Vinoperfect Radiance Serum', '8e3a594a-b73c-44b5-8275-dad58a46ed75', 'Serum', 'This lightweight, non-greasy serum is formulated to visibly reduce the appearance of dark spots and enhance skin radiance. It is suitable for all skin types, including sensitive skin, and is enriched with natural ingredients.', 'Brightening dull skin, reducing dark spots, and evening out skin tone.', 'The Caudalie Vinoperfect Radiance Serum is often 20-30% cheaper in French pharmacies compared to US retailers, making it a great deal for travelers.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/caudalie_vinoperfect_brightening_serum.png');
INSERT INTO public.products VALUES ('3f532c45-6b36-4d25-ae93-b80acf3277ba', 'Embryolisse Smoothing Eye Contour Care', '94b5edc5-ff74-4f1a-881b-c6a873ed0ce7', 'Eye Care', 'A lightweight yet nourishing eye cream designed to smooth fine lines, reduce puffiness, and brighten the under-eye area. Suitable for all skin types, including sensitive skin.', 'Addresses fine lines, puffiness, and dark circles while providing hydration to the delicate under-eye area.', 'Significant price savings in French pharmacies compared to US retailers, where prices are often marked up. Also, the product is more readily available in France.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/embryolisse_eye_contour_tube.png');
INSERT INTO public.products VALUES ('66305bae-2797-4053-afec-d2b2ce6d863a', 'Esthederm Intensive Vitamin C Serum', '98203ee4-b8f2-4254-861a-5462b99d8a51', 'Serum', 'This highly concentrated serum harnesses the power of stabilized vitamin C to brighten the skin, improve radiance, and reduce visible signs of pigmentation and aging. It also supports collagen production for firmer, smoother skin.', 'Targeting dark spots, dullness, uneven skin tone, and early signs of aging.', 'Institut Esthederm products are often cheaper in French pharmacies compared to US retailers. Additionally, the specific formulation is highly concentrated and less commonly found in US stores.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/institut_esthederm_vitamin_c_serum.png');
INSERT INTO public.products VALUES ('e5bbe766-61d0-4923-a678-d40afcedd45f', 'La Roche-Posay Pure Vitamin C10 Serum', 'ca37042e-8c7c-4e5f-8e51-e1e94b387385', 'Serum', 'This potent yet lightweight serum combines pure vitamin C with salicylic acid and neurosensine to brighten skin, reduce fine lines, and improve overall texture. Its non-greasy formula is ideal for sensitive skin and delivers visible results over time.', 'Dull skin, uneven texture, fine lines, and sensitive skin types seeking a brightening and anti-aging boost.', 'The French price for this serum is significantly lower than its US retail price. Additionally, the formula contains a high concentration of pure vitamin C and is often fresher when purchased in France due to higher turnover rates.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/la_roche-posay_vitamin_c_serum.png');
INSERT INTO public.products VALUES ('88501af3-53e8-4359-9b52-4138f1d92fce', 'Mela D Pigment Control Serum', 'ca37042e-8c7c-4e5f-8e51-e1e94b387385', 'Serum', 'Advanced dark spot correcting serum with patented PhE-Resorcinol. Reduces hyperpigmentation and evens skin tone.', 'Dark spots, hyperpigmentation, uneven skin tone, melasma', 'Stronger active concentrations in EU formula, dermatologist-trusted', false, true, false, false, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/lrp_mela_d_serum_dropper.png');
INSERT INTO public.products VALUES ('03e5ccea-1ad6-4dcf-a7dd-1cb8df7ca3e1', 'SVR Densitium Contour des Yeux', 'a85a20e0-f130-4c20-9c09-60aa21cbe365', 'Eye Care', 'This advanced eye cream is specifically designed to target wrinkles, dark circles, puffiness, and loss of firmness around the delicate eye area. Formulated with anti-aging peptides and hyaluronic acid, it hydrates, plumps, and brightens for a refreshed and youthful appearance.', 'Addressing signs of aging, dark circles, puffiness, and loss of elasticity around the eyes.', 'SVR products are often more affordable in France, and this eye cream is usually priced significantly lower there compared to international retailers.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/svr_densitium_eye_tube.png');
INSERT INTO public.products VALUES ('ffbefab1-7acb-44c3-be75-e72d8d158996', 'Retinal 0.5 Intensive Night Serum', 'a85a20e0-f130-4c20-9c09-60aa21cbe365', 'Serum', 'High-strength retinal serum for visible anti-aging results. More potent than retinol, with less irritation.', 'Fine lines, wrinkles, uneven texture, anti-aging', 'SVR retinal concentrations higher than US OTC limits, exclusive formula', true, true, true, false, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/svr_retinal_serum_dropper.png');
INSERT INTO public.products VALUES ('f45b8222-ed06-4977-b5ba-d69b47dc32b4', 'Uriage Age Protect Multi-Action Eye Contour', '5f0ab354-d914-4632-b0ee-36881aff538a', 'Eye Care', 'This multi-action eye cream targets fine lines, puffiness, and dark circles while protecting the delicate eye area from environmental stressors like blue light and pollution. Its lightweight texture absorbs quickly, making it ideal for both day and night use.', 'Women concerned with aging signs around the eye area, dark circles, puffiness, and environmental protection.', 'This product is often priced significantly lower in French pharmacies compared to US retailers, and larger sizes are more commonly available in France.', false, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/uriage_age_protect_eye.png');
INSERT INTO public.products VALUES ('87eb2614-4461-4a47-bb04-4d07912925c2', 'Uriage Bariésun Ultra-Light Fluid SPF50+', '5f0ab354-d914-4632-b0ee-36881aff538a', 'Sunscreen', 'A lightweight, fast-absorbing sunscreen for face and body, offering high protection against UVA and UVB rays. Enriched with Uriage thermal water, it hydrates and soothes skin while being water-resistant and non-comedogenic.', 'Ideal for all skin types, including sensitive skin, and provides high sun protection without leaving a greasy residue.', 'This sunscreen is significantly cheaper in French pharmacies compared to US retailers, and it contains EU-approved UV filters for superior sun protection.', true, true, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/uriage_sunscreen_bottle.png');
