INSERT INTO public.products VALUES ('afc8c428-c50e-4395-852a-49ef6852d3b9', 'Vichy Dercos Nutrients Detox Shampoo', 'be047683-8275-4206-837f-9fd9f455a557', 'Hair Care', 'This purifying shampoo is designed to detoxify hair and scalp from pollution and excess sebum. Formulated with spirulina extract and purifying charcoal, it leaves hair feeling fresh, light, and clean without stripping natural moisture.', 'Oily hair, pollution-exposed hair, and scalp prone to buildup or greasiness.', 'The price of this shampoo is significantly lower in French pharmacies compared to US retailers, and larger sizes are more easily available in France.', false, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/vichy_dercos_shampoo.png');
INSERT INTO public.products VALUES ('d0414af8-de5b-482c-86fc-88ae5a1dab97', 'Bioderma Photoderm Max Aquafluide SPF50+', '3f6b360c-e2ab-4204-98a9-5dd9f73bc584', 'Sunscreen', 'A lightweight, ultra-fluid sunscreen with SPF50+ that offers high UVA/UVB protection while feeling weightless on the skin. Perfect for face and body use, it leaves a matte finish without any oily residue.', 'Ideal for all skin types, including sensitive and combination skin, seeking broad-spectrum sun protection with a non-greasy, matte texture.', 'The French formula includes advanced EU-only UV filters (like Tinosorb S) for superior sun protection, and it''s significantly cheaper in France compared to US retailers.', true, true, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/bioderma_photoderm_sunscreen.png');
INSERT INTO public.products VALUES ('bcc2bf9e-e191-4cbe-85f3-c37a1a918ce8', 'Ducray Extra-Doux Dermoprotective Shampoo', 'a9955795-686a-4578-8813-4540e1811f8a', 'Hair Care', 'This gentle, dermoprotective shampoo is designed for frequent use by the entire family. Its soap-free formula respects the scalp''s natural balance while leaving hair soft, shiny, and easy to manage.', 'Ideal for sensitive scalps, frequent washing, and maintaining healthy, balanced hair.', 'Significantly cheaper in French pharmacies compared to US-based retailers and often available in large family-sized bottles not easily found in the US.', false, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/ducray_gentle_shampoo_bottle.png');
INSERT INTO public.products VALUES ('628a97ac-86b9-4748-83e4-070dd0f29f9a', 'Kerium Anti-Hairloss Shampoo', 'ca37042e-8c7c-4e5f-8e51-e1e94b387385', 'Hair Care', 'La Roche-Posay Kerium Anti-Hairloss Shampoo is specially formulated to address hair thinning and hair loss while gently cleansing the scalp. Enriched with anti-hair loss ingredients, it promotes microcirculation and strengthens hair fibers for visibly fuller, healthier-looking hair.', 'Ideal for individuals experiencing hair thinning, hair loss, or a sensitive scalp.', 'This product is more affordable in France compared to US retailers and is often harder to find in the US. French pharmacies stock the original formula with a better price point.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/la_roche-posay_hair_shampoo.png');
INSERT INTO public.products VALUES ('da47ef56-5679-470c-8a7e-92fe7ba47ed3', 'Lotion Tonique Douceur', 'ca37042e-8c7c-4e5f-8e51-e1e94b387385', 'Toner', 'A gentle, alcohol-free toner that removes residual impurities while soothing and hydrating sensitive skin. Formulated with La Roche-Posay thermal spring water for ultimate comfort.', 'Sensitive skin, post-cleansing hydration, removing cleanser residue', 'Significantly cheaper in French pharmacies and available in larger sizes not sold in the US.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/la_roche-posay_toner_bottle.png');
INSERT INTO public.products VALUES ('3e4fa8ab-4a20-496d-9560-07d662693245', 'Lierac Dioptiride Wrinkle Correction Filling Cream', '8cebffaa-ef68-4369-a08e-ff9cd70b17e3', 'Eye Care', 'Lierac Dioptiride Wrinkle Correction Filling Cream is an anti-aging eye treatment designed to visibly reduce fine lines, wrinkles, and signs of fatigue in the delicate eye area. Its light texture absorbs quickly, leaving the skin around the eyes smoother, hydrated, and refreshed.', 'Ideal for addressing early signs of aging, such as crow''s feet, fine lines, and under-eye wrinkles, while also providing hydration and soothing benefits.', 'Lierac is a French pharmacy brand and its products are often priced significantly lower in France than in the US, making it a cost-effective purchase during your trip. Additionally, this specific product may be harder to find in US stores.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/lierac_eye_cream_jar.png');
INSERT INTO public.products VALUES ('34307267-df4b-4ca5-a900-0811ed5f5dc6', 'Eau Florale de Rose Bio', '1dea8445-f3d0-4503-9737-72daffe5fb58', 'Toner', 'A certified organic rose floral water that tones, refreshes, and prepares the skin for moisturizer. Gentle enough for all skin types including sensitive.', 'All skin types, refreshing, toning, preparation for skincare routine', 'Nuxe organic line is primarily sold in France with limited US availability, making it a perfect France-only find.', false, true, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/nuxe_rose_floral_water_bottle.png');
INSERT INTO public.products VALUES ('5b987635-f138-4541-b7b6-040d63cfc8ba', 'Phytolaque Botanical Hair Spray', 'f8f0614b-a9c7-42b7-a29f-0db4c23c2702', 'Hair Care', 'Natural-hold hairspray with plant-based polymers. Provides flexible hold without stiffness or residue.', 'All hair types needing light hold, natural styling, brushable finish', 'Plant-based French formulas unavailable in US, significantly lower prices', false, true, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/phyto_hair_spray_can.png');
