INSERT INTO public.products VALUES ('e0dbf869-a8e4-4de7-8e3d-90188ece2025', 'SVR Ampoule Anti-Ox [C20] Vitamin C Serum', 'a85a20e0-f130-4c20-9c09-60aa21cbe365', 'Serum', 'This high-potency serum contains 20% stabilized Vitamin C to brighten the skin, improve radiance, and reduce signs of aging. Its lightweight, fast-absorbing formula is perfect for all skin types, including sensitive skin.', 'Dullness, uneven skin tone, fine lines, and antioxidant protection for all skin types.', 'This serum is significantly more affordable in France, where it is priced lower than in the US. Additionally, the product is not widely available in US retailers.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/svr_vitamin_c_ampoule.png');
