INSERT INTO public.products VALUES ('c955ccc8-8d08-4a73-b3a3-d6cd155207e5', 'Lipikar Syndet AP+ Cleansing Cream', 'ca37042e-8c7c-4e5f-8e51-e1e94b387385', 'Body Care', 'Gentle cleansing cream designed for dry and sensitive skin. Provides long-lasting hydration while cleansing, ideal for the whole family.', 'Dry skin, sensitive skin, eczema-prone skin', 'Often more affordable than in the US, especially for larger sizes.', true, false, false, true, '/images/products/la_roche_posay_lipikar_syndet_ap_cleansing_cream.png');
