INSERT INTO public.products VALUES ('43373e0d-3629-436f-bd85-1794fdbee366', 'Bioderma Sensibio H2O Micellar Water', '3f6b360c-e2ab-4204-98a9-5dd9f73bc584', 'Cleanser', 'This cult-favorite micellar water gently cleanses and removes makeup while respecting the skin''s natural balance. Perfect for sensitive skin, it leaves the face feeling soft and refreshed without any need for rinsing.', 'Sensitive skin, makeup removal, gentle cleansing for all skin types', 'Significantly cheaper in France than in the US, with larger sizes available at a better value.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/bioderma_micellar_water_bottle.png');
INSERT INTO public.products VALUES ('24808c90-93e2-41c6-b1df-efb026a617d8', 'Caudalie Premier Cru The Cream', '8e3a594a-b73c-44b5-8275-dad58a46ed75', 'Moisturizer', 'An advanced anti-aging cream that targets all signs of aging, including wrinkles, loss of firmness, dark spots, and hydration. This luxurious cream is formulated with patented Vinergy® technology to enhance skin''s energy and boost the effectiveness of its active ingredients.', 'Ideal for mature skin or anyone looking to address wrinkles, fine lines, uneven skin tone, and loss of elasticity.', 'Significantly cheaper in France compared to US prices, plus often available in exclusive value sets in French pharmacies.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/caudalie_premier_cru_jar.png');
INSERT INTO public.products VALUES ('f5086c07-b016-400b-9679-db568ad3e822', 'Embryolisse Lait-Crème Concentré', '94b5edc5-ff74-4f1a-881b-c6a873ed0ce7', 'Moisturizer', 'A multi-purpose moisturizing cream that delivers hydration, soothes irritation, and primes the skin for makeup. Renowned for its rich yet non-greasy formula, it’s a favorite among makeup artists and skincare enthusiasts alike.', 'Ideal for all skin types, especially dry and sensitive skin. Perfect for use as a daily moisturizer, primer, or even a hydrating mask.', 'This cult classic is significantly cheaper in French pharmacies compared to US retailers, making it a must-buy for travelers.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/embryolisse_moisturizer_tube.png');
