INSERT INTO public.products VALUES ('bd5ba6f6-02d5-4a61-b947-b44dace3a935', 'Klorane Shampoo with Nettle', '10ea18e0-9fab-4ecc-baa8-f436bef887e2', 'Hair Care', 'This purifying shampoo is specially formulated for oily hair to regulate sebum production and prolong the time between washes. Made with nettle extract, it gently cleanses while leaving hair light, fresh, and balanced.', 'Ideal for those with oily scalps or hair that tends to get greasy quickly, helping to control excess oil and maintain freshness.', 'This product is significantly cheaper in French pharmacies compared to US prices and is often available in larger sizes that are not distributed in the US.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/klorane_nettle_shampoo.png');
INSERT INTO public.products VALUES ('4a36f671-742f-4c1f-9a77-37426a23c5c7', 'Lierac Rosilogie Persistent Redness Neutralizing Cream', '8cebffaa-ef68-4369-a08e-ff9cd70b17e3', 'Treatment', 'A targeted cream specifically formulated to address persistent redness and visible blood vessels associated with rosacea. It provides instant soothing and long-term reduction of redness through a combination of botanical and dermatological actives.', 'Soothing and reducing redness for sensitive or rosacea-prone skin. Ideal for reducing visible blood vessels and calming irritation.', 'This product is more affordable in French pharmacies compared to US retailers, and Lierac products can be difficult to find in the US in their original formulations.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/lierac_anti-redness_cream_tube.png');
