INSERT INTO public.products VALUES ('8b523e8d-6a55-4937-abd4-c5c05bc5b8c9', 'Aqualia Thermal Rehydrating Serum', 'be047683-8275-4206-837f-9fd9f455a557', 'Serum', 'A lightweight hydrating serum formulated with 97% natural-origin ingredients to deliver intense hydration to dehydrated skin. Enriched with Vichy Mineralizing Thermal Water and hyaluronic acid, this serum locks in moisture and strengthens the skin barrier.', 'Ideal for dehydrated, sensitive, or dry skin seeking long-lasting hydration and a plumping effect.', 'Significant price savings and availability of larger sizes in French pharmacies compared to US retail.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/vichy_aqualia_serum_bottle.png');
