INSERT INTO public.products VALUES ('a143c555-b0c9-4460-a68d-ae28767ddfa9', 'Avène Antirougeurs Fort Relief Concentrate', '2399c263-bccb-4e12-bdef-d95f449ae372', 'Treatment', 'A targeted treatment designed to reduce redness and calm discomfort associated with rosacea and sensitive skin. With its concentrated formula, it works to strengthen the skin''s barrier and provide long-lasting relief.', 'Ideal for individuals with rosacea, redness-prone skin, or sensitive skin seeking relief from irritation and visible redness.', 'This product is significantly cheaper in French pharmacies compared to US retail prices, and the formula contains EU-approved soothing ingredients that may not be as common in US formulations.', true, false, false, true, '/attached_assets/generated_images/avène_fort_concentrate_dropper.png');
