INSERT INTO public.products VALUES ('56b37111-ee7a-4c4c-ad3d-7a9cfaeb772e', 'A313 Pommade Retinol', '2399c263-bccb-4e12-bdef-d95f449ae372', 'Treatment', 'Legendary French pharmacy retinoid that rivals prescription-strength treatments. Available OTC in France.', 'Anti-aging, acne, smoothing skin texture, fading hyperpigmentation', 'This prescription-strength retinoid is only available OTC in French pharmacies.', true, true, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/a313_retinol_tube.png');
INSERT INTO public.products VALUES ('a0594d24-7106-46ac-a460-b646929be216', 'Crème Apaisante Anti-Rougeurs', '2399c263-bccb-4e12-bdef-d95f449ae372', 'Treatment', 'This soothing anti-redness cream is specifically formulated for sensitive, redness-prone skin, offering immediate relief and long-term care. Enriched with thermal spring water, it calms irritation while reducing visible redness over time.', 'Ideal for individuals with rosacea, redness-prone skin, or sensitivity triggered by environmental factors.', 'This product is significantly cheaper in France, with prices often 30-40% lower than US retail. Additionally, the French version contains patented EU-only soothing agents.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/avene_anti-redness_cream_tube.png');
INSERT INTO public.products VALUES ('e19d91c0-764c-4663-9fc9-539f38b25c68', 'Avène PhysioLift Eyes', '2399c263-bccb-4e12-bdef-d95f449ae372', 'Eye Care', 'A targeted anti-aging eye cream that reduces the appearance of wrinkles, puffiness, and dark circles while smoothing and firming the delicate eye area. Formulated with Avène''s Thermal Spring Water for soothing hydration.', 'Ideal for women looking to address fine lines, puffiness, and dark circles around the eyes while maintaining hydration and comfort for sensitive skin.', 'In France, this product is often 20-30% less expensive than in the US, making it a great deal when purchased directly from French pharmacies.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/avene_eye_cream_tube.png');
INSERT INTO public.products VALUES ('f962c26d-a7f9-4e9d-9afc-dea82ece9caf', 'Hydrance Intense Rehydrating Serum', '2399c263-bccb-4e12-bdef-d95f449ae372', 'Serum', 'This lightweight hydrating serum is formulated with Avène''s patented Cohederm complex and thermal spring water to deliver long-lasting hydration and soothe sensitive skin. It helps restore the skin''s natural moisture barrier, leaving it soft, plump, and radiant.', 'Ideal for dehydrated, sensitive, or irritation-prone skin needing deep hydration and moisture barrier repair.', 'This product is significantly cheaper in French pharmacies compared to US prices, often by 30-40%. Additionally, larger sizes are sometimes available in France.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/avene_hydrating_serum_dropper.png');
INSERT INTO public.products VALUES ('c898d20b-da4a-4c6a-9902-199e050ace7a', 'Cold Cream Lip Balm', '2399c263-bccb-4e12-bdef-d95f449ae372', 'Lip Care', 'The Avène Cold Cream Lip Balm is a rich, nourishing treatment designed to soothe and repair dry, chapped, or cracked lips. Formulated with the iconic Avène Thermal Spring Water, it delivers intense hydration and protection for sensitive skin.', 'Ideal for very dry, sensitive, or damaged lips that need deep hydration and repair.', 'This product is significantly cheaper in French pharmacies compared to US retailers, often available for nearly half the price.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/avene_lip_balm_stick.png');
INSERT INTO public.products VALUES ('9c56dacf-2bfc-407d-9a5f-43d524506e19', 'Avène Very High Protection Lotion SPF50+', '2399c263-bccb-4e12-bdef-d95f449ae372', 'Sunscreen', 'A lightweight, water-resistant sunscreen formulated with advanced UVA and UVB filters to protect even the most sensitive skin. Enriched with Avène Thermal Spring Water, it soothes and calms while providing powerful sun protection for both face and body.', 'Ideal for sensitive skin, including those prone to redness or irritation, and provides broad-spectrum protection against harmful UV rays.', 'This product contains EU-approved UV filters like Tinosorb S, which are not FDA-approved in the US, offering enhanced sun protection. It is also significantly cheaper in French pharmacies compared to similar products available in the US.', true, true, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/avene_spf50_sunscreen_tube.png');
INSERT INTO public.products VALUES ('09bdaa87-c345-42e0-9852-d46633edb97f', 'Atoderm Intensive Baume', '3f6b360c-e2ab-4204-98a9-5dd9f73bc584', 'Moisturizer', 'Ultra-soothing, lipid-replenishing balm for very dry, irritated atopic skin. Contains patented Skin Barrier Therapy technology.', 'Extremely dry skin, atopic dermatitis, eczema, winter skin', 'Significantly cheaper in France, available in large 500ml pump bottles not sold in US', false, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/bioderma_atoderm_pump_bottle.png');
INSERT INTO public.products VALUES ('00dc5349-9301-4d5d-a85e-e01c60effa1e', 'Cicabio Baume', '3f6b360c-e2ab-4204-98a9-5dd9f73bc584', 'Treatment', 'Multi-purpose repairing balm that soothes and repairs damaged skin. Contains antalgicine for comfort.', 'Minor cuts, burns, irritations, tattoo aftercare, post-procedure skin', 'French pharmacists recommend for all skin emergencies, larger tubes available', false, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/bioderma_cicabio_tube.png');
INSERT INTO public.products VALUES ('8e96903a-6482-4d75-9f11-6bd220bfb895', 'Hydrabio Serum', '3f6b360c-e2ab-4204-98a9-5dd9f73bc584', 'Serum', 'Lightweight hydrating serum that reactivates skin''s ability to retain moisture.', 'Dehydrated skin, travel-stressed skin, pre-flight moisture boost', 'Perfect travel size and fragrance-free. Much cheaper in France.', false, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/bioderma_hydrating_serum_bottle.png');
INSERT INTO public.products VALUES ('bec5ed80-f0c9-48ea-b8f9-0e57b568af10', 'Cleanance Cleansing Gel', '2399c263-bccb-4e12-bdef-d95f449ae372', 'Cleanser', 'Gentle foaming cleanser designed for oily and acne-prone skin. Effectively removes impurities while respecting the skin''s natural balance.', 'Oily skin, acne, excess sebum, daily cleansing', 'Significantly lower price compared to US retail options.', true, false, false, true, '/images/products/avene_cleanance_cleansing_gel.png');
INSERT INTO public.products VALUES ('e8dbf5bb-be95-4a22-b7e5-9f049638bcb2', 'Hydrance Rich Hydrating Cream', '2399c263-bccb-4e12-bdef-d95f449ae372', 'Moisturizer', 'Luxurious, rich cream that deeply hydrates and nourishes dry skin. Ideal for providing lasting moisture and comfort.', 'Dehydrated skin, dry patches, sensitive skin', 'Often available at a lower price compared to US retailers, making it a smart buy.', true, false, false, true, '/images/products/avene_hydrance_rich_hydrating_cream.png');
INSERT INTO public.products VALUES ('4a5c6345-8c55-46bf-9741-eae3e8be37a6', 'Cicabio Restorative Lip Balm', '3f6b360c-e2ab-4204-98a9-5dd9f73bc584', 'Lip Care', 'A nourishing and repairing lip balm designed to soothe and restore damaged or chapped lips. Its rich yet non-greasy formula provides hydration and protection for sensitive lips.', 'Ideal for those with dry, chapped, or irritated lips, as well as for lips exposed to extreme weather conditions.', 'The price in French pharmacies is significantly lower compared to US retailers, and the formula is highly regarded for its efficiency and simplicity.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/bioderma_lip_balm_tube.png');
INSERT INTO public.products VALUES ('8be6cdf3-a865-4de9-827e-fff79ec5aa93', 'Cattier Nourishing Lip Care with Shea Butter', '51082607-615b-4fc9-a921-bac265497b84', 'Lip Care', 'A rich and hydrating lip balm formulated with organic shea butter and jojoba oil to deeply nourish, repair, and protect dry or chapped lips. Its creamy texture glides on smoothly, leaving lips soft and supple.', 'Ideal for dry, cracked, or sensitive lips needing intense hydration and protection from environmental stressors.', 'Cattier products are often significantly cheaper in France, and this lip balm is hard to find in the US, making it a great value purchase during a trip.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/cattier_organic_lip_balm.png');
INSERT INTO public.products VALUES ('a41707a4-09af-4c5a-ae94-d70a674fa944', 'Caudalie Resveratrol-Lift Firming Eye Gel-Cream', '8e3a594a-b73c-44b5-8275-dad58a46ed75', 'Eye Care', 'This lightweight gel-cream is formulated to reduce puffiness, smooth fine lines, and firm the eye area, helping to restore a youthful appearance. Enriched with Caudalie''s patented Resveratrol and hyaluronic acid, it offers anti-aging benefits while hydrating delicate skin.', 'Ideal for those concerned with fine lines, wrinkles, puffiness, and loss of firmness around the eyes.', 'It is typically 25-30% cheaper in French pharmacies compared to US prices, making it a great deal for travelers.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/caudalie_eye_cream_jar.png');
INSERT INTO public.products VALUES ('270bcfac-276a-464c-86c7-198e972e6247', 'Caudalie Resveratrol-Lift Firming Night Cream', '8e3a594a-b73c-44b5-8275-dad58a46ed75', 'Treatment', 'This luxurious anti-aging night cream is formulated to visibly firm, lift, and smooth the skin while you sleep. Powered by Caudalie''s patented Resveratrol technology, it works synergistically with hyaluronic acid and vegan collagen to restore skin''s elasticity and reduce the appearance of fine lines and wrinkles.', 'Ideal for women experiencing early to advanced signs of aging, including loss of firmness, fine lines, and a lack of hydration.', 'This product is significantly more affordable in French pharmacies compared to US retailers, often costing up to 30% less.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/caudalie_resveratrol_jar.png');
INSERT INTO public.products VALUES ('ce70e4f2-28bd-4295-8e6a-43e17b77343a', 'Sérum SOS Désaltérant', '8e3a594a-b73c-44b5-8275-dad58a46ed75', 'Serum', 'This ultra-hydrating serum is enriched with organic grape water and hyaluronic acid to provide long-lasting hydration and soothe dehydrated skin. Its lightweight, non-greasy formula absorbs quickly, leaving the skin plump, radiant, and refreshed.', 'Ideal for dehydrated, sensitive, or dull skin in need of intense hydration and a radiant boost.', 'This product is significantly cheaper in French pharmacies compared to US retailers, often by 20-30%. Additionally, French pharmacies frequently offer exclusive bundles or travel sizes not available in other markets.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/caudalie_sos_thirst_serum.png');
