INSERT INTO public.products VALUES ('b91908c8-05d7-4c85-940e-1aa572dbb171', 'Filorga Time-Filler Absolute Wrinkle Correction Cream', 'c82df969-a916-45dd-ab88-9ac148305a8f', 'Treatment', 'A potent anti-aging cream inspired by aesthetic medicine techniques, designed to reduce the appearance of all types of wrinkles, including fine lines, deep wrinkles, and expression lines. Its rich texture delivers intense hydration while smoothing and plumping the skin.', 'Ideal for women looking to prevent and reduce visible signs of aging, including wrinkles, loss of firmness, and dehydration.', 'Filorga products are significantly cheaper in French pharmacies compared to US retailers, and this cream often comes in larger sizes or exclusive promo sets unavailable in the US.', true, false, false, true, 'https://vqrjlwnooaxahidjjyru.supabase.co/storage/v1/object/public/product-images/filorga_anti-aging_cream_jar.png');
