INSERT INTO public.product_ingredients VALUES ('8b8e03c8-dda2-4332-931f-3c0507305138', '66cf0cae-59e4-4556-bf38-c82c3137fbc0', 'fe2d7fad-8b80-4bec-ba1d-04daad84a7d0', true);
INSERT INTO public.review_summaries VALUES ('1bd7d46b-e98e-428d-9a55-03d3081fbf42', '135a1bb9-a01a-4b05-8646-2f167ab16e9f', 'editorial', 'Dermatologists call this the gold standard for sun protection.');
INSERT INTO public.review_summaries VALUES ('fd435b25-4c77-4e15-ace7-dfeef66a693b', '7a250ed6-1663-46f1-9171-90885f958193', 'user', 'Saved my skin after a harsh peel. It calms redness overnight.');
INSERT INTO public.review_summaries VALUES ('9e4c6ce9-c7d8-42d6-b631-c6a942752d67', '628a97ac-86b9-4748-83e4-070dd0f29f9a', 'user', 'Users report noticeable improvements in hair strength and reduced hair loss after consistent use. Many with sensitive scalps appreciate its gentle formula.');
INSERT INTO public.review_summaries VALUES ('94d9f850-d404-42df-aad7-9dd0e5faeb71', 'b91908c8-05d7-4c85-940e-1aa572dbb171', 'user', 'Users rave about its ability to visibly reduce wrinkles and improve skin texture within weeks. Many appreciate its luxurious texture and how well it hydrates without feeling heavy.');
INSERT INTO public.review_summaries VALUES ('0bd71103-f67a-474e-af66-481f1b95fe40', 'a0fcd0e8-0f51-4d51-ae9a-19609d56cae4', 'user', 'Users love how gentle yet effective this night balm is for reducing wrinkles and improving skin texture. Many note waking up with softer, firmer, and more radiant skin.');
INSERT INTO public.review_summaries VALUES ('d8568cc9-1507-4679-a624-adfb6a28c690', '50a94ae3-dacc-47a4-b188-a42ecf27b355', 'user', 'Users praise this cream for its rich texture and noticeable anti-aging effects, often highlighting its luxurious feel and ability to deeply hydrate dry skin.');
INSERT INTO public.review_summaries VALUES ('cae65092-4976-46c5-b5cd-37a77503117d', '270bcfac-276a-464c-86c7-198e972e6247', 'editorial', 'Dermatologists and beauty editors praise this night cream for its rich texture and visible results in improving skin plumpness and elasticity. Users report waking up to smoother, more radiant skin after consistent use.');
INSERT INTO public.review_summaries VALUES ('7bccd91a-a3b7-431f-bc47-3d3c2d10d093', '24808c90-93e2-41c6-b1df-efb026a617d8', 'user', 'Users praise the luxurious texture and noticeable improvement in skin firmness and radiance after consistent use. Many highlight it as a go-to anti-aging cream for mature skin.');
INSERT INTO public.review_summaries VALUES ('aa600241-a78b-4a50-9e54-affb67d5063d', '9f94759b-a9d5-4cf8-be4a-bdde39a590fa', 'user', 'Users praise this cream for its lightweight texture that delivers deep hydration and visibly reduces wrinkles with regular use. Many appreciate the smooth finish it leaves on their skin.');
INSERT INTO public.review_summaries VALUES ('b624a621-0a8a-442f-9833-6ec348b512ee', 'efe4666b-af5b-4f62-95eb-610a7bf59eaf', 'user', 'Users rave about the luxurious texture and the way this cream instantly makes the skin feel smoother and more hydrated. Many have noticed a visible improvement in fine lines and skin firmness with consistent use.');
INSERT INTO public.review_summaries VALUES ('8e328d74-2b1f-4a70-b811-aab1a014279f', '385fa00a-9371-4e11-acc0-61c607b76656', 'user', 'Users praise this cream for its rich texture and visible improvement in skin firmness and hydration. Many reviewers with mature or post-menopausal skin report feeling their skin is more supple and nourished after regular use.');
INSERT INTO public.review_summaries VALUES ('86926254-62a0-4772-8b1d-2a8e86121019', 'd34e9efc-7eea-434b-b3a3-b0c7b1195c08', 'user', 'Users appreciate the hydrating, non-greasy texture and report smoother, firmer skin with regular use. Many note its gentle formula as suitable for sensitive skin.');
INSERT INTO public.review_summaries VALUES ('b6bf6c99-0e17-42d4-a651-5a8e5cf6067f', '75e84c4d-c1f9-426f-9edd-ef9c6f4eb690', 'editorial', 'Highly praised for its lightweight texture and anti-aging benefits, users appreciate its non-greasy finish and potent sun protection. Many consider it a must-have for daily use, especially in sunny climates.');
INSERT INTO public.review_summaries VALUES ('1484721e-5b3d-475a-b0c6-ed44c8edad6c', '9c56dacf-2bfc-407d-9a5f-43d524506e19', 'user', 'Users rave about its non-greasy texture and the way it absorbs quickly into the skin. Many highlight its suitability for sensitive skin and its superior sun protection compared to US sunscreens.');
INSERT INTO public.review_summaries VALUES ('dbff6429-10a5-4f94-a5f6-90157d223903', 'd0414af8-de5b-482c-86fc-88ae5a1dab97', 'user', 'Users love this sunscreen for its lightweight feel, non-greasy texture, and high sun protection. It''s particularly praised for not leaving a white cast and working well under makeup.');
INSERT INTO public.review_summaries VALUES ('0334bb4a-78dc-4af0-bbd7-795a2e7c229c', 'a4f04a7e-f291-41c7-95e0-950dce16ee84', 'user', 'Users rave about the lightweight texture, ease of application, and non-greasy finish. Many highlight its effectiveness in preventing sunburn even after prolonged sun exposure, and it is especially praised for being gentle on sensitive skin.');
INSERT INTO public.review_summaries VALUES ('45132990-b622-45b7-ba00-b72ed3672261', '82f07f7a-cd05-4dcc-8c12-d0ac7e279373', 'user', 'Users rave about its unique texture and ability to smooth skin while providing excellent sun protection. Many appreciate its lightweight feel and compatibility with makeup.');
INSERT INTO public.review_summaries VALUES ('e88997c1-4507-4b4d-a9f2-b7b09cfae911', '87eb2614-4461-4a47-bb04-4d07912925c2', 'user', 'Users appreciate the lightweight texture and non-greasy finish, reporting it as a great option for sensitive skin and daily use. Many highlight its affordability in France compared to other high-quality sunscreens.');
INSERT INTO public.review_summaries VALUES ('1a32bcc1-ddb8-4a44-bd1e-225ea463aba9', 'e19d91c0-764c-4663-9fc9-539f38b25c68', 'user', 'Users praise this eye cream for its lightweight yet effective formula, noting visible improvements in puffiness and fine lines without causing irritation. It''s highly recommended for those with sensitive skin.');
INSERT INTO public.review_summaries VALUES ('e3282ba9-16a3-4769-baa3-644211989873', 'b2c1cbb8-1b34-4d98-baa9-0430c2e61d89', 'editorial', 'Praised for its luxurious texture and visible results, this eye cream is a go-to for those seeking to brighten and firm the delicate eye area. Users appreciate its lightweight feel and rapid absorption.');
INSERT INTO public.review_summaries VALUES ('7b622340-5853-4e93-bfdc-b14fe3faf2a9', 'a41707a4-09af-4c5a-ae94-d70a674fa944', 'user', 'Users praise this eye gel-cream for its lightweight texture and visible results in reducing puffiness and fine lines. Many note its quick absorption and suitability for sensitive skin.');
INSERT INTO public.review_summaries VALUES ('492b9540-f576-408d-89af-d0c6dc736d24', '09b2aab0-251c-4447-bf97-e589da6544d9', 'user', 'Users praise this eye cream for its lightweight texture and ability to reduce the appearance of dark circles with regular use. Many highlight its affordability in France compared to US prices.');
INSERT INTO public.review_summaries VALUES ('c06433f1-12f5-4dfe-8727-e9fecf949188', '03e5ccea-1ad6-4dcf-a7dd-1cb8df7ca3e1', 'user', 'Users praise this product for its lightweight texture and fast-absorbing formula, noting visible improvements in dark circles and under-eye puffiness within weeks. Many consider it a great value compared to pricier alternatives.');
INSERT INTO public.review_summaries VALUES ('d6347689-50cf-40c3-8f84-38e725a8637a', 'f45b8222-ed06-4977-b5ba-d69b47dc32b4', 'user', 'Users praise the Uriage Age Protect Multi-Action Eye Contour for its effective hydrating and anti-aging benefits. Many reviewers have noted visible improvements in dark circles and puffiness after consistent use.');
INSERT INTO public.review_summaries VALUES ('0add6fc5-6b33-40b2-b893-98388b68b026', '3e4fa8ab-4a20-496d-9560-07d662693245', 'user', 'Users praise the Lierac Dioptiride Wrinkle Correction Filling Cream for its ability to smooth fine lines and hydrate the eye area without causing irritation. Many consider it a staple in their anti-aging skincare routine.');
INSERT INTO public.review_summaries VALUES ('ba14e909-6725-431b-8a71-fcfca7bc5fa3', '3f532c45-6b36-4d25-ae93-b80acf3277ba', 'user', 'Users praise this eye cream for its lightweight texture and ability to reduce puffiness and hydrate the under-eye area, making it a staple in their skincare routine.');
INSERT INTO public.review_summaries VALUES ('35d30402-5b2a-4496-acb6-c57888f41890', '475d9286-e3a5-4fa5-8f93-a97b7ca3cece', 'user', 'Users frequently praise this serum for its efficacy in fading hyperpigmentation and brightening the skin. Many appreciate its gentle formula and noticeable results after consistent use.');
INSERT INTO public.review_summaries VALUES ('9fb635f1-3973-43f2-83ea-1cc97e241877', 'e5bbe766-61d0-4923-a678-d40afcedd45f', 'user', 'Users praise the La Roche-Posay Pure Vitamin C10 Serum for its ability to brighten dull skin, reduce the appearance of fine lines, and leave skin looking healthier. Many highlight its lightweight texture and suitability for sensitive skin.');
INSERT INTO public.review_summaries VALUES ('0d1a0c33-0114-4937-9408-235032605074', '66305bae-2797-4053-afec-d2b2ce6d863a', 'user', 'Users praise this serum for its ability to visibly brighten the skin and fade dark spots within weeks of consistent use. Its lightweight texture absorbs quickly without leaving a sticky residue.');
INSERT INTO public.review_summaries VALUES ('93282dd6-44ba-409d-a069-4f7503cb4c06', 'e0dbf869-a8e4-4de7-8e3d-90188ece2025', 'editorial', 'Experts praise this serum for its high concentration of stabilized Vitamin C, making it an effective product for brightening and anti-aging. Users love its lightweight feel and noticeable results in improving skin radiance.');
INSERT INTO public.review_summaries VALUES ('12495d65-da5f-4ec0-b2e2-3fe18de8c972', '76d54451-286d-4bf6-97d4-5cedb17c576f', 'user', 'Users praise this serum for its lightweight texture and noticeable brightening effects. Many note that it helps reduce the appearance of dark spots and improves overall skin tone without causing irritation.');
INSERT INTO public.review_summaries VALUES ('b3ae0491-1921-421e-91f6-e3d627751c97', '1de2ad4c-2676-48cf-839c-afcdd6fbc72b', 'user', 'Users love the fresh, floral scent and how quickly the serum absorbs into the skin. Many report a noticeable improvement in their skin''s glow and softness after consistent use.');
INSERT INTO public.review_summaries VALUES ('531877e4-24b2-4330-8114-613df4919a0c', 'b7727466-06e2-4352-b0c0-1a55ba52ae66', 'user', 'Users praise this serum for its ability to brighten and rejuvenate dull skin. Many note visible improvements in skin tone and texture within a few weeks of use, with the added benefit of a non-greasy formula.');
INSERT INTO public.review_summaries VALUES ('5f841967-003f-4f51-b7b5-0aa62db4151b', 'c23ba109-035a-489a-8f94-ac7f4aef281f', 'user', 'Users rave about the lightweight texture and noticeable improvement in skin tone and smoothness. Many appreciate its effectiveness on pigmentation and fine lines without causing irritation.');
INSERT INTO public.review_summaries VALUES ('ca276ed4-fe11-4dfd-a9f5-fbdbc7a1670a', '48cea062-519c-425a-adcb-31dc0085abe2', 'user', 'Users love the lightweight texture, subtle floral scent, and visible brightening effects after consistent use. Many appreciate its dual function as a serum and primer.');
INSERT INTO public.review_summaries VALUES ('b9e2aace-7132-4a2d-b0d8-7b240f18c6f9', 'bda99054-6071-44cd-8325-48f97a5ec63c', 'user', 'Users love this serum for its ability to brighten skin and improve texture within weeks. Many report it absorbs quickly without leaving a sticky residue, making it a favorite for layering under moisturizers.');
